using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class TicketModelTrainer
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<TicketModelTrainer> _logger;

    // Category labels in the order ML.NET maps them (alphabetical by default).
    private static readonly string[] CategoryLabels = ["Billing", "General", "Technical"];

    public TicketModelTrainer(IWebHostEnvironment env, ILogger<TicketModelTrainer> logger)
    {
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "ticket_model.zip");
        _logger = logger;
    }

    /// <summary>
    /// Trains the model, evaluates it on a held-out test split, saves the
    /// model to disk, and returns evaluation metrics.
    /// </summary>
    public TrainingResult TrainAndEvaluate()
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // 80/20 train-test split
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label")
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate(
                "Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(mlContext)
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        ITransformer model = pipeline.Fit(split.TrainSet);

        // Evaluate on held-out test set
        IDataView predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation(
            "Evaluation — MicroAccuracy: {Micro:F4}, MacroAccuracy: {Macro:F4}, LogLoss: {LogLoss:F4}",
            metrics.MicroAccuracy, metrics.MacroAccuracy, metrics.LogLoss);

        // Build per-class metrics from the confusion matrix
        var perClass = new List<PerClassMetric>();
        var cm = metrics.ConfusionMatrix;
        for (int i = 0; i < cm.PerClassPrecision.Count; i++)
        {
            string className = i < CategoryLabels.Length ? CategoryLabels[i] : $"Class{i}";
            double precision = cm.PerClassPrecision[i];
            double recall = cm.PerClassRecall[i];
            double f1 = (precision + recall) > 0
                ? 2 * precision * recall / (precision + recall)
                : 0;

            perClass.Add(new PerClassMetric
            {
                ClassName = className,
                Precision = precision,
                Recall = recall,
                F1Score = f1,
            });

            _logger.LogInformation(
                "  {Class}: Precision={P:F4}, Recall={R:F4}, F1={F1:F4}",
                className, precision, recall, f1);
        }

        // Save the trained model
        mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);

        return new TrainingResult
        {
            Message = "Model trained and saved successfully.",
            MicroAccuracy = (float)metrics.MicroAccuracy,
            MacroAccuracy = (float)metrics.MacroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction,
            PerClassMetrics = perClass,
        };
    }

    public string ModelPath => _modelPath;
    public bool ModelExists => File.Exists(_modelPath);
}

